// src/pages/test/paginate-to-csv.tsx

import React, { useState } from "react";
import { useExportSubmissionsCSV } from "../../components/ppm/forms/useExportSubmissionsCSV";
import { getSupabase } from "../../database/supabase";

const ExportSubmissionsPage = () => {
  const [rows, setRows] = useState<any[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  const { exportCSV, loading, error } = useExportSubmissionsCSV({
    pageSize: 500
  });

  const loadData = async () => {
    try {
      setLoadingData(true);

      const supabase = await getSupabase();

      const { data, error } = await supabase
        .from("form_submissions")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(50); // just preview, not full dump

      if (error) throw error;

      setRows(data || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoadingData(false);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>Export Submissions Test</h1>

      <button
        onClick={loadData}
        style={{
          padding: "10px 16px",
          marginBottom: 20,
          background: "#111",
          color: "#fff",
          border: "none",
          borderRadius: 6,
          cursor: "pointer"
        }}
      >
        {loadingData ? "Loading..." : "Load Data"}
      </button>

      {rows.length > 0 && (
        <>
          <div style={{ marginBottom: 20 }}>
            <button
              onClick={exportCSV}
              disabled={loading}
              style={{
                padding: "10px 16px",
                background: "#0a7",
                color: "#fff",
                border: "none",
                borderRadius: 6,
                cursor: "pointer"
              }}
            >
              {loading ? "Generating CSV..." : "Download CSV"}
            </button>
          </div>

          <div
            style={{
              border: "1px solid #ddd",
              borderRadius: 8,
              padding: 12,
              maxHeight: 500,
              overflow: "auto",
              background: "#fafafa"
            }}
          >
            {rows.map((row, idx) => (
              <div
                key={row.id || idx}
                style={{
                  marginBottom: 12,
                  paddingBottom: 8,
                  borderBottom: "1px solid #eee"
                }}
              >
                <div style={{ fontSize: 12, opacity: 0.6 }}>
                  {row.form_id} — {row.created_at}
                </div>

                <div style={{ fontSize: 14 }}>
                  {Object.entries(row.data || {})
                    .map(([k, v]) => `${k}: ${v}`)
                    .join(", ")}
                </div>
              </div>
            ))}
          </div>
        </>
      )}

      {error && <p style={{ color: "red" }}>{error}</p>}
    </div>
  );
};

export default ExportSubmissionsPage;